    die "Usage: $0 [latitude1] [longitude1] [latitude2] [longitude2]\n";
}

# Validate inputs
if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
    die "Please provide four arguments: latitude1, longitude1, latitude2, longitude2.\n";
}

# Validate latitude and longitude ranges
if (!($lat1 =~ /^-?\d+(\.\d+)?$/ || $lat1 =~ /^-?\d+\.?\d+$/)) {
    die "Invalid latitude: $lat1. Must be a number.\n";
}

if (!($lon1 =~ /^-?\d+(\.\d+)?$/ || $lon1 =~ /^-?\d+\.?\d+$/)) {
    die "Invalid longitude: $lon1. Must be a number.\n";
}

if (!($lat2 =~ /^-?\d+(\.\d+)?$/ || $lat2 =~ /^-?\d+\.?\d+$/)) {
    die "Invalid latitude: $lat2. Must be a number.\n";
}

if (!($lon2 =~ /^-?\d+(\.\d+)?$/ || $lon2 =~ /^-?\d+\.?\d+$/)) {
    die "Invalid longitude: $lon2. Must be a number.\n";
}

# Convert latitude and longitude to radians
sub to_radians {
    return radians($_[0]);
}

sub radians {
    return $_[0] * pi / 180;
}

# Haversine formula
sub haversine {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371;  # Radius of Earth in kilometers

    my $dLat = to_radians($lat2 - $lat1);
    my $dLon = to_radians($lon2 - $lon1);

    my $a = sin($dLat/2) ** 2 + cos(to_radians($lat1)) * cos(to_radians($lat2)) * sin($dLon/2) ** 2;
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Calculate distance
